<?php declare(strict_types=1); namespace App\Services\Attendance; use App\Enums\EnrollmentStatus; use App\Models\Classroom; use App\Models\StudentAttendance; use App\Models\StudentEnrollment; use App\Services\ActivityLogger; use Illuminate\Support\Facades\DB; use Illuminate\Validation\ValidationException;
class StudentAttendanceService{public function __construct(private ActivityLogger $logger){} public function bulk(Classroom $classroom,string $date,array $rows):void{DB::transaction(function()use($classroom,$date,$rows){$active=StudentEnrollment::where('classroom_id',$classroom->id)->where('enrollment_status',EnrollmentStatus::Active->value)->pluck('academic_year_id','student_id'); foreach($rows as $studentId=>$row){if(!isset($active[$studentId]))throw ValidationException::withMessages(['students'=>'Siswa tanpa enrollment aktif tidak boleh dimasukkan.']); $a=StudentAttendance::updateOrCreate(['student_id'=>$studentId,'attendance_date'=>$date],['classroom_id'=>$classroom->id,'academic_year_id'=>$active[$studentId],'status'=>$row['status'],'notes'=>$row['notes']??null,'recorded_by'=>auth()->id()]); $this->logger->log('student-attendance.saved',$a,[],$a->toArray());}});}}
